diff --git a/llvm/include/llvm/Analysis/ValueLattice.h b/llvm/include/llvm/Analysis/ValueLattice.h
index 9357a15f7619..eddc88fc8a76 100644
--- a/llvm/include/llvm/Analysis/ValueLattice.h
+++ b/llvm/include/llvm/Analysis/ValueLattice.h
@@ -17,6 +17,7 @@
 //===----------------------------------------------------------------------===//

 namespace llvm {
+class Instruction;

 /// This class represents lattice values for constants.
 ///
@@ -469,7 +470,8 @@ public:
   /// evaluated.
   Constant *getCompare(CmpInst::Predicate Pred, Type *Ty,
                        const ValueLatticeElement &Other,
-                       const DataLayout &DL) const;
+                       const DataLayout &DL,
+                       const Instruction *I = nullptr) const;

   /// Combine two sets of facts about the same value into a single set of
   /// facts.  Note that this method is not suitable for merging facts along
diff --git a/llvm/lib/Analysis/ConstantFolding.cpp b/llvm/lib/Analysis/ConstantFolding.cpp
index 88db315ffd0b..e33845280a2e 100644
--- a/llvm/lib/Analysis/ConstantFolding.cpp
+++ b/llvm/lib/Analysis/ConstantFolding.cpp
@@ -1303,41 +1303,94 @@ Constant *llvm::FlushFPConstant(Constant *Operand, const Instruction *I,
   if (!I || !I->getParent() || !I->getFunction())
     return Operand;

-  ConstantFP *CFP = dyn_cast<ConstantFP>(Operand);
-  if (!CFP)
-    return Operand;
-
-  const APFloat &APF = CFP->getValueAPF();
-  // TODO: Should this canonicalize nans?
-  if (!APF.isDenormal())
-    return Operand;
-
-  Type *Ty = CFP->getType();
-  DenormalMode DenormMode =
-      I->getFunction()->getDenormalMode(Ty->getFltSemantics());
-  DenormalMode::DenormalModeKind Mode =
-      IsOutput ? DenormMode.Output : DenormMode.Input;
-  switch (Mode) {
-  default:
-    llvm_unreachable("unknown denormal mode");
-  case DenormalMode::Dynamic:
-    return nullptr;
-  case DenormalMode::IEEE:
-    return Operand;
-  case DenormalMode::PreserveSign:
-    if (APF.isDenormal()) {
+  // Handle scalar floating-point constants directly.
+  if (auto *CFP = dyn_cast<ConstantFP>(Operand)) {
+    const APFloat &APF = CFP->getValueAPF();
+    // TODO: Should this canonicalize nans?
+    if (!APF.isDenormal())
+      return Operand;
+
+    Type *Ty = CFP->getType();
+    DenormalMode DenormMode =
+        I->getFunction()->getDenormalMode(Ty->getFltSemantics());
+    DenormalMode::DenormalModeKind Mode =
+        IsOutput ? DenormMode.Output : DenormMode.Input;
+    switch (Mode) {
+    default:
+      llvm_unreachable("unknown denormal mode");
+    case DenormalMode::Dynamic:
+      return nullptr;
+    case DenormalMode::IEEE:
+      return Operand;
+    case DenormalMode::PreserveSign:
       return ConstantFP::get(
           Ty->getContext(),
           APFloat::getZero(Ty->getFltSemantics(), APF.isNegative()));
-    }
-    return Operand;
-  case DenormalMode::PositiveZero:
-    if (APF.isDenormal()) {
+    case DenormalMode::PositiveZero:
       return ConstantFP::get(Ty->getContext(),
                              APFloat::getZero(Ty->getFltSemantics(), false));
     }
-    return Operand;
   }
+
+  // Handle fixed-width vector floating-point constants element-wise.
+  Type *OpTy = Operand->getType();
+  if (OpTy->isVectorTy() && OpTy->getScalarType()->isFloatingPointTy()) {
+    // We only know how to examine fixed-width constant vectors.
+    auto *VTy = cast<VectorType>(OpTy);
+    if (!isa<FixedVectorType>(VTy))
+      return Operand;
+
+    unsigned NumElts = cast<FixedVectorType>(VTy)->getNumElements();
+    SmallVector<Constant *, 16> Elts;
+    Elts.reserve(NumElts);
+
+    const fltSemantics &Sem = OpTy->getScalarType()->getFltSemantics();
+    DenormalMode DenormMode = I->getFunction()->getDenormalMode(Sem);
+    DenormalMode::DenormalModeKind Mode =
+        IsOutput ? DenormMode.Output : DenormMode.Input;
+
+    // If the mode is Dynamic, and any element is a denormal, we cannot fold.
+    bool AnyDenorm = false;
+
+    for (unsigned i = 0; i != NumElts; ++i) {
+      Constant *Elt = Operand->getAggregateElement(i);
+      if (auto *EltFP = dyn_cast_or_null<ConstantFP>(Elt)) {
+        const APFloat &APF = EltFP->getValueAPF();
+        if (APF.isDenormal()) {
+          AnyDenorm = true;
+          switch (Mode) {
+          default:
+            llvm_unreachable("unknown denormal mode");
+          case DenormalMode::Dynamic:
+            // Bail out entirely; caller should not fold.
+            return nullptr;
+          case DenormalMode::IEEE:
+            // Keep as-is.
+            break;
+          case DenormalMode::PreserveSign:
+            Elt = ConstantFP::get(
+                OpTy->getContext(),
+                APFloat::getZero(Sem, APF.isNegative()));
+            break;
+          case DenormalMode::PositiveZero:
+            Elt = ConstantFP::get(OpTy->getContext(),
+                                   APFloat::getZero(Sem, false));
+            break;
+          }
+        }
+      }
+      // If element is not a ConstantFP (undef/poison/aggregatezero etc), keep it.
+      Elts.push_back(Elt ? Elt : UndefValue::get(OpTy->getScalarType()));
+    }
+
+    // If we replaced any elements (non-IEEE mode with denormals), build new vector.
+    // If no denormals were present, just return the original operand.
+    if (!AnyDenorm || Mode == DenormalMode::IEEE)
+      return Operand;
+
+    return ConstantVector::get(Elts);
+  }
+
   return Operand;
 }

