diff --git a/llvm/lib/Transforms/Utils/SCCPSolver.cpp b/llvm/lib/Transforms/Utils/SCCPSolver.cpp
index 4225e7e80fda..05a932767835 100644
--- a/llvm/lib/Transforms/Utils/SCCPSolver.cpp
+++ b/llvm/lib/Transforms/Utils/SCCPSolver.cpp
@@ -1604,7 +1604,7 @@ void SCCPInstVisitor::visitCmpInst(CmpInst &I) {
   auto V1State = getValueState(Op1);
   auto V2State = getValueState(Op2);

-  Constant *C = V1State.getCompare(I.getPredicate(), I.getType(), V2State, DL);
+  Constant *C = V1State.getCompare(I.getPredicate(), I.getType(), V2State, DL, &I);
   if (C) {
     ValueLatticeElement CV;
     CV.markConstant(C);

